SELECT ID, WORKPLACE_ID, USER_ID, ROLE, HOURLY_WAGE, STATUS
FROM WORKPLACE_MEMBERS
WHERE WORKPLACE_ID = #{workplaceId}
  AND USER_ID = #{userId}
  AND STATUS = 'ACTIVE'

SELECT ID, WORKPLACE_ID, USER_ID, ROLE, HOURLY_WAGE, STATUS
FROM WORKPLACE_MEMBERS
WHERE WORKPLACE_ID = #{workplaceId}
  AND USER_ID = #{userId}
  AND ROLE = 'OWNER'
  AND STATUS = 'ACTIVE'
